// Rank YouTube videos from the last 48h by view count, take top 10.
// Input: YouTube videos.list response (snippet + statistics for up to 50 IDs).

const items = $input.first().json.items || [];

const ranked = items
  .filter(v => v && v.id && v.statistics && v.statistics.viewCount)
  .map(v => {
    const thumbs = v.snippet && v.snippet.thumbnails ? v.snippet.thumbnails : {};
    const thumb = thumbs.medium || thumbs.high || thumbs.default || {};
    return {
      videoId: v.id,
      title: v.snippet ? v.snippet.title : '',
      channel: v.snippet ? v.snippet.channelTitle : '',
      publishedAt: v.snippet ? v.snippet.publishedAt : '',
      thumbnailUrl: thumb.url || '',
      viewCount: parseInt(v.statistics.viewCount, 10) || 0,
      url: `https://www.youtube.com/watch?v=${v.id}`
    };
  })
  // Defence-in-depth: drop anything with no title or channel
  .filter(v => v.title && v.channel)
  .sort((a, b) => b.viewCount - a.viewCount)
  .slice(0, 10);

return [{ json: { videos: ranked } }];

// Bundle research inputs into a single context blob for the LLM,
// AND build the entire Anthropic request body here so the HTTP node
// just forwards it. This sidesteps n8n's expression-interpolation
// breaking the outer JSON when raw XML/quotes leak into the prompt.

const rss = $('Fetch Disney Parks Blog RSS').first()?.json?.data
         ?? $('Fetch Disney Parks Blog RSS').first()?.json
         ?? '';
const parks = $('Fetch themeparks.wiki destinations').first()?.json ?? {};
const videos = $('Rank Top 10 by views').first()?.json?.videos ?? [];

// Today's date in Eastern Time (YYYY-MM-DD) — slug + display
const now = new Date();
const etDate = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'America/New_York',
  year: 'numeric', month: '2-digit', day: '2-digit'
}).format(now);

const slug = `parkio-daily-${etDate}`;
const niceDate = new Date(etDate + 'T00:00:00Z').toLocaleDateString('en-US', {
  timeZone: 'UTC', month: 'long', day: 'numeric', year: 'numeric'
});

const rssText    = typeof rss === 'string' ? rss.slice(0, 30000) : JSON.stringify(rss).slice(0, 30000);
const parksJson  = JSON.stringify(parks).slice(0, 5000);
const videosJson = JSON.stringify(videos);

// Build the prompt as a JS template literal. JS handles escaping
// so the resulting string is safe to embed inside JSON.stringify().
const prompt = `You are writing the Parkio Daily briefing for ${etDate}.

Output ONE JSON object — no commentary, no markdown fences — that conforms exactly to the schema below.

GUARDRAILS — read carefully, follow strictly:
1. Do NOT invent breaking news. Every breaking-news item must be supported by the Disney Parks Blog RSS feed below or by a clearly newsworthy themeparks.wiki status (e.g. "Test Track closed for refurbishment"). If nothing newsworthy is in the source data, set "sections.breaking" to [].
2. If overall source data is weak (no real news today), respond with a single bignews item titled "No major updates today" and a short body noting the parks are operating normally. Set sections.breaking and sections.icymi to [].
3. Every factual claim — names, dates, closures, openings — MUST come from the provided source data. If you can't ground a claim, drop the item.
4. Tone: helpful, fast, guest-focused. No clickbait. No emojis. Short sentences.
5. Each video summary is 1–2 sentences and based ONLY on the video's title + channel. Do not invent details about what's inside the video.
6. Use the EXACT 10 videos provided in TOP 10 YOUTUBE VIDEOS — copy each field verbatim and add a "summary" field.

SCHEMA (produce this object):
{
  "title": string,
  "slug": string (must equal "${slug}"),
  "date": string (must equal "${etDate}"),
  "teaser": string (1–2 sentences, ≤160 chars; SEO + email teaser),
  "rightNow": {
    "headline": "Best rides right now",
    "rides": [ { "name": string, "parkSlug": string, "note": string } ]   // 2–3 items
  },
  "sections": {
    "breaking":   [ { "title", "body", "parkSlug?", "source?": { "label", "url" } } ],   // 0–2
    "bignews":    [ ... same shape ],                                                     // 1–3
    "topstories": [ ... same shape ],                                                     // 2–4
    "icymi":      [ ... same shape ],                                                     // 1–3
    "spotlight":  [ { "title", "body", "parkSlug?", "ctaLabel?" } ]                       // exactly 1
  },
  "videos": [
    { "title", "channel", "url", "thumbnailUrl", "videoId", "viewCount", "publishedAt", "summary" }
  ]
}

parkSlug enum: magic-kingdom | epcot | hollywood-studios | animal-kingdom | disneyland | california-adventure.

RESEARCH — Disney Parks Blog RSS:
${rssText}

RESEARCH — themeparks.wiki destinations summary:
${parksJson}

TOP 10 YOUTUBE VIDEOS (last 48h, ranked by views — copy verbatim into "videos", add a 1–2 sentence "summary" for each):
${videosJson}

Return the JSON object only.`;

// JSON.stringify handles ALL escaping (quotes, backslashes, newlines, control chars).
const claudeBody = JSON.stringify({
  model: 'claude-sonnet-4-5',
  max_tokens: 5000,
  messages: [{ role: 'user', content: prompt }]
});

return [{
  json: {
    today: etDate,
    slug,
    title: `Parkio Daily — ${niceDate}`,
    videos,        // pass-through for the validate step
    claudeBody     // pre-stringified Anthropic request body
  }
}];

// Parse Claude's text output, validate the shape, attach metadata,
// and produce the GitHub commit payload.
// Throws on schema violation — better to skip a day than ship junk.

const resp = $input.first().json;
const text = resp?.content?.[0]?.text ?? '';
if (!text) throw new Error('Claude returned no text content');

// Strip any accidental markdown fence
const jsonStr = text
  .replace(/^```(?:json)?\s*/i, '')
  .replace(/```\s*$/, '')
  .trim();

let post;
try {
  post = JSON.parse(jsonStr);
} catch (e) {
  throw new Error('Claude output is not valid JSON: ' + e.message + '\n---\n' + jsonStr.slice(0, 500));
}

// --- Required top-level fields ---
const required = ['title', 'slug', 'date', 'teaser'];
for (const k of required) {
  if (!post[k] || typeof post[k] !== 'string') {
    throw new Error(`Missing required field: ${k}`);
  }
}
if (!/^parkio-daily-\d{4}-\d{2}-\d{2}$/.test(post.slug)) {
  throw new Error(`Slug doesn't match parkio-daily-YYYY-MM-DD: ${post.slug}`);
}
if (post.teaser.length > 220) {
  throw new Error(`Teaser too long (${post.teaser.length} chars)`);
}

// --- parkSlug enum check across all sections + rightNow ---
const VALID_PARKS = ['magic-kingdom','epcot','hollywood-studios','animal-kingdom','disneyland','california-adventure'];
for (const sec of Object.values(post.sections ?? {})) {
  if (!Array.isArray(sec)) continue;
  for (const item of sec) {
    if (item.parkSlug && !VALID_PARKS.includes(item.parkSlug)) {
      throw new Error(`Invalid parkSlug: ${item.parkSlug}`);
    }
  }
}
for (const ride of (post.rightNow?.rides ?? [])) {
  if (ride.parkSlug && !VALID_PARKS.includes(ride.parkSlug)) {
    throw new Error(`Invalid rightNow parkSlug: ${ride.parkSlug}`);
  }
}

// --- Videos: must be 0..10 items, each with required fields ---
if (!Array.isArray(post.videos)) {
  throw new Error('post.videos must be an array');
}
if (post.videos.length > 10) {
  post.videos = post.videos.slice(0, 10);
}
for (const v of post.videos) {
  for (const k of ['title', 'channel', 'url', 'summary']) {
    if (!v[k] || typeof v[k] !== 'string') {
      throw new Error(`Video missing field: ${k}`);
    }
  }
  if (typeof v.viewCount !== 'undefined' && typeof v.viewCount !== 'number') {
    v.viewCount = parseInt(v.viewCount, 10) || 0;
  }
}

// --- Auto-attach internal metadata so the website renders the AI badge ---
post.updatedAt = new Date().toISOString();
post.type = 'daily-briefing';
post.meta = Object.assign(
  {
    aiGenerated: true,
    sources: [
      'Disney Parks Blog RSS',
      'themeparks.wiki destinations',
      'YouTube Data API v3 (top 10 last 48h)'
    ],
    generatedAt: new Date().toISOString()
  },
  post.meta || {}
);

// Detect "no real news today" fallback
const breaking = post.sections?.breaking ?? [];
const big = post.sections?.bignews ?? [];
if (breaking.length === 0 && big.some(b => /no major updates/i.test(b.title))) {
  post.meta.fallbackReason = 'no-news';
}

return [{
  json: {
    slug: post.slug,
    post,
    fileContent: JSON.stringify(post, null, 2)
  }
}];

// Build the Beehiiv teaser-only email payload from the validated post.
// HARD RULE (docs/AUTOMATION.md): the email contains ONLY teaser + 3 bullets + link.
// No YouTube content. No section bodies. The full briefing lives on the website.

const wrap = $('Validate + format JSON').first().json;
const post = wrap.post;
const slug = wrap.slug;

const sec = post.sections || {};

// Pick the strongest 3 bullets — prefer breaking → bignews → topstories.
const candidates = [];
const pushIf = (arr) => {
  if (Array.isArray(arr)) {
    for (const item of arr) {
      if (item && item.title) candidates.push(item.title);
    }
  }
};
pushIf(sec.breaking);
pushIf(sec.bignews);
pushIf(sec.topstories);

// Dedupe + cap at 3
const seen = new Set();
const bullets = [];
for (const t of candidates) {
  const key = t.trim().toLowerCase();
  if (!seen.has(key)) {
    seen.add(key);
    bullets.push(t.trim());
    if (bullets.length === 3) break;
  }
}

const url = `https://parkio.info/guide/${slug}`;
const bulletHtml = bullets.map(b =>
  `<li style="margin:6px 0;">${b}</li>`
).join('');

const bodyHtml = `
<div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;font-size:16px;line-height:1.5;color:#111;">
  <p style="margin:0 0 16px 0;">${post.teaser}</p>
  <ul style="padding-left:20px;margin:0 0 20px 0;">${bulletHtml}</ul>
  <p style="margin:24px 0;">
    <a href="${url}" style="display:inline-block;background:#0A84FF;color:#fff;text-decoration:none;padding:12px 20px;border-radius:14px;font-weight:600;">Read the full briefing →</a>
  </p>
  <p style="margin:24px 0 8px 0;font-size:14px;color:#555;">
    Or jump straight in: <a href="https://parkio.info/parks">Open Parkio</a> · <a href="https://parkio.info/parks">Check live waits</a>
  </p>
  <p style="font-size:12px;color:#888;margin-top:32px;">Parkio Daily — fresh every morning at 6 AM ET.</p>
</div>
`.trim();

const previewText = post.teaser.length > 100 ? post.teaser.slice(0, 97) + '...' : post.teaser;

return [{
  json: {
    title: post.title,
    subtitle: post.teaser,
    preview_text: previewText,
    body_content: bodyHtml,
    slug,
    canonical_url: url
  }
}];
